"use client";

import { useState, useEffect } from "react";
import { Plus, Search, MoreHorizontal, X } from "lucide-react"; // Adicionamos o X aqui

interface Alpinista {
    id: number;
    nome: string;
    email: string;
    telefone: string;
    foto?: string;
}

export default function AlpinistasPage() {
    // Estados da Lista
    const [alpinistas, setAlpinistas] = useState<Alpinista[]>([]);
    const [carregando, setCarregando] = useState(true);
    const [erro, setErro] = useState("");

    // --- NOVOS ESTADOS DO MODAL ---
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [nome, setNome] = useState("");
    const [email, setEmail] = useState("");
    const [telefone, setTelefone] = useState("");
    const [salvando, setSalvando] = useState(false); // Para mostrar um "Salvando..." no botão

    useEffect(() => {
        buscarAlpinistas();
    }, []);

    // Função auxiliar para pegar o token
    const getCookie = (nomeCookie: string) => {
        const valor = `; ${document.cookie}`;
        const partes = valor.split(`; ${nomeCookie}=`);
        if (partes.length === 2) return partes.pop()?.split(';').shift();
        return null;
    };

    // Função Read (GET)
    const buscarAlpinistas = async () => {
        try {
            const token = getCookie('sia_token');
            if (!token) throw new Error("Token não encontrado.");

            const resposta = await fetch("http://localhost:8000/api/alpinistas/", {
                method: "GET",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${token}` 
                }
            });

            if (!resposta.ok) throw new Error("Erro ao carregar a lista.");
            
            const dados = await resposta.json();
            setAlpinistas(dados);
        } catch (error: any) {
            setErro(error.message);
        } finally {
            setCarregando(false);
        }
    };

    // --- NOVA FUNÇÃO CREATE (POST) ---
    const salvarAlpinista = async (e: React.FormEvent) => {
        e.preventDefault(); // Evita que a página recarregue ao dar submit no form
        setSalvando(true);

        try {
            const token = getCookie('sia_token');
            
            const resposta = await fetch("http://localhost:8000/api/alpinistas/", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${token}` 
                },
                // Transformamos nossos estados em JSON para o Django entender
                body: JSON.stringify({
                    nome: nome,
                    email: email,
                    telefone: telefone
                })
            });

            if (!resposta.ok) throw new Error("Não foi possível salvar o alpinista.");

            // Se deu tudo certo: 
            setIsModalOpen(false); // 1. Fecha o Modal
            setNome(""); // 2. Limpa os campos
            setEmail("");
            setTelefone("");
            buscarAlpinistas(); // 3. Pede pro Django a lista atualizada para a tabela piscar com o novo dado

        } catch (error: any) {
            alert(error.message);
        } finally {
            setSalvando(false);
        }
    };

    return (
        <div className="space-y-6 relative">
            
            <div className="flex justify-between items-center bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                <div>
                    <h1 className="text-2xl font-bold text-gray-800">Alpinistas</h1>
                    <p className="text-sm text-gray-500 mt-1">Gerencie os membros do Movimento Escalada.</p>
                </div>
                {/* Ao clicar, mudamos o estado para true, abrindo o Modal */}
                <button 
                    onClick={() => setIsModalOpen(true)}
                    className="bg-escalada-azul hover:bg-blue-800 text-white px-5 py-2.5 rounded-lg font-medium flex items-center gap-2 transition-colors shadow-sm"
                >
                    <Plus size={20} />
                    Novo Alpinista
                </button>
            </div>

            <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex gap-4">
                <div className="flex-1 relative">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Search className="h-5 w-5 text-gray-400" />
                    </div>
                    <input 
                        type="text" 
                        placeholder="Buscar por nome, email ou telefone..." 
                        className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-escalada-azul/20 focus:border-escalada-azul transition-all"
                    />
                </div>
            </div>

            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                {carregando && <div className="p-10 text-center text-gray-500">Carregando dados...</div>}
                {erro && <div className="p-10 text-center text-red-500 bg-red-50">{erro}</div>}
                {!carregando && !erro && alpinistas.length === 0 && (
                    <div className="p-10 text-center text-gray-500">Nenhum alpinista cadastrado.</div>
                )}

                {!carregando && !erro && alpinistas.length > 0 && (
                    <div className="overflow-x-auto">
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr className="bg-gray-50 border-b border-gray-100 text-sm text-gray-500 uppercase tracking-wider">
                                    <th className="px-6 py-4 font-medium">Nome</th>
                                    <th className="px-6 py-4 font-medium">E-mail</th>
                                    <th className="px-6 py-4 font-medium">Telefone</th>
                                    <th className="px-6 py-4 font-medium text-right">Ações</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-100">
                                {alpinistas.map((alpinista) => (
                                    <tr key={alpinista.id} className="hover:bg-gray-50 transition-colors">
                                        <td className="px-6 py-6 flex items-center gap-4">
                                            {alpinista.foto ? (
                                                <img src={alpinista.foto} alt="Foto" className="w-12 h-12 rounded-full object-cover border border-gray-200 shadow-sm" />
                                            ) : (
                                                <div className="w-12 h-12 rounded-full bg-blue-50 text-escalada-azul flex items-center justify-center font-bold text-base border border-blue-100 shadow-sm">
                                                    {alpinista.nome.charAt(0).toUpperCase()}
                                                </div>
                                            )}
                                            <span className="text-base font-medium text-gray-900">{alpinista.nome}</span>
                                        </td>
                                        <td className="px-6 py-6 text-sm text-gray-500">{alpinista.email || "-"}</td>
                                        <td className="px-6 py-6 text-sm text-gray-500">{alpinista.telefone || "-"}</td>
                                        <td className="px-6 py-6 text-sm text-right">
                                            <button className="text-gray-400 hover:text-escalada-azul transition-colors p-2 rounded-lg hover:bg-blue-50">
                                                <MoreHorizontal size={24} />
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            {/* --- O MODAL --- */}
            {/* Só renderiza esse bloco se isModalOpen for true */}
            {isModalOpen && (
                // Fundo escuro transparente (z-50 garante que fica por cima de tudo)
                <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
                    
                    {/* A caixa branca do Modal */}
                    <div className="bg-white rounded-2xl shadow-xl w-full max-w-md overflow-hidden">
                        
                        {/* Cabeçalho do Modal */}
                        <div className="flex justify-between items-center p-6 border-b border-gray-100">
                            <h2 className="text-xl font-bold text-gray-800">Novo Alpinista</h2>
                            <button 
                                onClick={() => setIsModalOpen(false)}
                                className="text-gray-400 hover:text-gray-600 transition-colors"
                            >
                                <X size={24} />
                            </button>
                        </div>

                        {/* Formulário */}
                        <form onSubmit={salvarAlpinista} className="p-6 space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Nome Completo *</label>
                                <input 
                                    type="text" 
                                    required
                                    value={nome}
                                    onChange={(e) => setNome(e.target.value)}
                                    className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-escalada-azul/20 focus:border-escalada-azul"
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">E-mail</label>
                                <input 
                                    type="email" 
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                    className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-escalada-azul/20 focus:border-escalada-azul"
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Telefone</label>
                                <input 
                                    type="tel" 
                                    value={telefone}
                                    onChange={(e) => setTelefone(e.target.value)}
                                    className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-escalada-azul/20 focus:border-escalada-azul"
                                />
                            </div>

                            {/* Botões do Rodapé */}
                            <div className="flex justify-end gap-3 pt-4 mt-6 border-t border-gray-100">
                                <button 
                                    type="button"
                                    onClick={() => setIsModalOpen(false)}
                                    className="px-5 py-2 text-sm font-medium text-gray-600 hover:bg-gray-50 rounded-lg transition-colors"
                                >
                                    Cancelar
                                </button>
                                <button 
                                    type="submit"
                                    disabled={salvando}
                                    className="px-5 py-2 text-sm font-medium text-white bg-escalada-azul hover:bg-blue-800 rounded-lg transition-colors disabled:opacity-50"
                                >
                                    {salvando ? "Salvando..." : "Salvar Alpinista"}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

        </div>
    );
}